import socket
import threading
import json
import math

class GameServer:
    def __init__(self, host='localhost', port=5555):
        self.server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server.bind((host, port))
        self.server.listen()
        self.clients = []
        self.player_positions = {}

    def client_handler(self, conn, addr):
        print(f"New connection from {addr}")
        self.clients.append(conn)
        try:
            while True:
                data = conn.recv(1024)
                if not data:
                    break
                player_data = json.loads(data.decode('utf-8'))
                player_id = player_data['id']
                self.player_positions[player_id] = player_data['position']
                self.broadcast_game_state()
        finally:
            conn.close()
            self.clients.remove(conn)
            if player_id in self.player_positions:
                del self.player_positions[player_id]
            print(f"Connection closed from {addr}")

    def broadcast_game_state(self):
        game_state = json.dumps(self.player_positions).encode('utf-8')
        for client in self.clients:
            try:
                client.sendall(game_state)
            except:
                self.clients.remove(client)

    def start(self):
        print("Game server started")
        while True:
            conn, addr = self.server.accept()
            threading.Thread(target=self.client_handler, args=(conn, addr)).start()

